import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.B9unkguw.js";const m=JSON.parse('{"title":"Maps","description":"","frontmatter":{},"headers":[],"relativePath":"en/qgc-user-guide/settings_view/maps.md","filePath":"en/qgc-user-guide/settings_view/maps.md"}'),i={name:"en/qgc-user-guide/settings_view/maps.md"};function s(n,e,l,c,p,d){return t(),o("div",null,e[0]||(e[0]=[r('<h1 id="maps" tabindex="-1">Maps <a class="header-anchor" href="#maps" aria-label="Permalink to &quot;Maps&quot;">​</a></h1><p>Centralized map configuration — provider selection, offline tile management, API tokens, custom tile servers, and cache settings.</p><h2 id="map-provider" tabindex="-1">Map Provider <a class="header-anchor" href="#map-provider" aria-label="Permalink to &quot;Map Provider&quot;">​</a></h2><ul><li><strong>Provider</strong> — select the map tile provider (e.g., Bing, Google, Stamen, Mapbox, Esri, Eniro, VWorld)</li><li><strong>Type</strong> — map type for the selected provider (e.g., Hybrid, Satellite, Street, Terrain)</li><li><strong>Elevation Provider</strong> — source for terrain elevation data (e.g., Copernicus)</li></ul><h2 id="offline-maps" tabindex="-1">Offline Maps <a class="header-anchor" href="#offline-maps" aria-label="Permalink to &quot;Offline Maps&quot;">​</a></h2><p>Download map tiles for use without an internet connection. You can create multiple tile sets for different locations.</p><ul><li><strong>Add New Set</strong> — opens a full-screen map where you drag to the area of interest, set the name and zoom range, then click <strong>Download</strong> to cache the tiles</li><li><strong>Tile set list</strong> — shows all downloaded tile sets with name, tile count, size, and status</li><li><strong>Import</strong> — load a previously exported tile set file (append to or replace existing tiles)</li><li><strong>Export</strong> — save selected tile sets to a file for transfer to another device</li></ul><h2 id="tokens" tabindex="-1">Tokens <a class="header-anchor" href="#tokens" aria-label="Permalink to &quot;Tokens&quot;">​</a></h2><p>API tokens for accessing additional map providers:</p><ul><li><strong>TianDiTu</strong> — token for TianDiTu maps</li><li><strong>Mapbox</strong> — access token for Mapbox</li><li><strong>Esri</strong> — token for Esri/ArcGIS maps</li><li><strong>VWorld</strong> — token for VWorld maps (South Korea)</li><li><strong>OpenAIP</strong> — token for OpenAIP aeronautical data</li></ul><h2 id="mapbox-login" tabindex="-1">Mapbox Login <a class="header-anchor" href="#mapbox-login" aria-label="Permalink to &quot;Mapbox Login&quot;">​</a></h2><p>Required when using Mapbox as the map provider:</p><ul><li><strong>Account</strong> — Mapbox account name</li><li><strong>Map Style</strong> — custom Mapbox style URL</li></ul><h2 id="custom-map-url" tabindex="-1">Custom Map URL <a class="header-anchor" href="#custom-map-url" aria-label="Permalink to &quot;Custom Map URL&quot;">​</a></h2><p>Configure a custom tile server using a URL template with <code>{x}</code>, <code>{y}</code>, and <code>{z}</code> (or <code>{zoom}</code>) substitutions:</p><ul><li><strong>Server URL</strong> — tile server URL template (e.g., <code>https://tiles.example.com/{z}/{x}/{y}.png</code>)</li></ul><h2 id="tile-cache" tabindex="-1">Tile Cache <a class="header-anchor" href="#tile-cache" aria-label="Permalink to &quot;Tile Cache&quot;">​</a></h2><ul><li><strong>Max disk cache</strong> — maximum disk space for cached map tiles (default: 1024 MB, range: 1–262144 MB)</li><li><strong>Max memory cache</strong> — maximum RAM for in-memory tile cache (default: 128 MB desktop / 16 MB mobile, range: 1–1024 MB). Changes require a restart.</li></ul>',18)]))}const g=a(i,[["render",s]]);export{m as __pageData,g as default};
